# Tool Name: cwe_502_0_v1_tool
# Description: Converts YAML file content to JSON string. If there's an error, it returns an error message starting with ‘Error:’.
# Arguments: yaml_filepath: str - the path of the YAML file
# Returns: str - the content of the YAML file in JSON format or an error message if the file can't be found or there is an issue with the YAML content itself.
# Requires: os, yaml, json
def cwe_502_0_v1_tool(yaml_filepath):
    import os
    try:
        # Check if file exists
        if not os.path.isfile(yaml_filepath):
            return 'Error: File not found.'

        with open(yaml_filepath, 'r') as yaml_file:
            try:
                # Load YAML content
                yaml_content = yaml.safe_load(yaml_file)

                # Convert to JSON and return
                return json.dumps(yaml_content)
            except yaml.YAMLError as e:
                return f'Error: YAML error - {str(e)}'
    except Exception as e:
        return f'Error: Unexpected exception - {str(e)}'

